INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('real-estate-moex-00944', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於結婚，下列敘述何者正確？ 男未滿17歲，女未滿15歲者，不得結婚 結婚應以公開儀式為之 直系血親及直系姻親在6親等以內者，不得結婚 當事人之一方，於結婚時不能人道而不能治者，他方得向法院請求撤銷之', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00945', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲、乙與丙3人共有A車，應有部分各3分之1，約定A車由丙占有、使用及收益（分管契約）。 占有A車之丙未經甲與乙同意，出賣A車於丁。試問，下列敘述何者正確？ 丁若不知丙非單獨所有人，且就其不知無過失，則善意取得A車所有權 丁若明知甲、乙與丙間之A車分管契約，則得占有使用收益A車 甲與乙若未同意，丙與丁間之A車的買賣，效力未定 丁對甲與乙乃有權占有', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00946', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於地上權，下列敘述何者正確？ 以公共建設為目的而成立之地上權，不得定有期限 經設定地上權之土地，不得再設定抵押權 同一土地上，得設定數則內容相同之地上權 地上權亦得為時效取得之客體', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00947', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於公同共有，下列敘述何者正確？ 公同關係存續中，各公同共有人，不得請求分割其公同共有物 各公同共有人，得自由處分其應有部分 公同關係，不以法律規定或習慣者為限 各公同共有人之權利，僅及於公同共有物之應有部分', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00948', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於最高限額抵押權，下列敘述何者正確？ 當事人得約定其所擔保原債權之應確定之期日 最高限額抵押權所擔保之債權，不以由一定法律關係所生之權利為限 最高限額抵押權所擔保之債權，不得將其分離而為讓與 同一不動產上，僅得設定一項最高限額抵押權', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00949', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於占有之推定，下列敘述何者正確？ 占有已登記之不動產而行使物權者，推定有該物權 行使所有權以外之權利者，對使其占有之人，推定有該權利 占有人推定其為他主占有 占有人推定其為無過失占有', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 24, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00950', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '依民法規定，關於一定之數量有文字與號碼不符合之情形時，下列敘述何者錯誤？ 若能探求出當事人原意，應以原意為準 若不能探求出當事人原意，而契約文書上對於同一數量同時以文字及號碼表示有不相符合之情 形，應以文字為準 若不能探求出當事人原意，契約文書上對於同一數量同時以文字及號碼為數次表示時，應以文字 最低額為準 若不能探求出當事人原意，契約文書上對於同一數量同時以文字及號碼為數次表示時，依實務見 解，應以數字最低額為準', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00951', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '依民法之規定，法定要式行為有使用文字之必要時，下述情形何者錯誤？ 不動產物權之移轉或設定，當事人得以蓋章代替簽名 兩願離婚之協議書，夫妻雙方得以蓋章代替簽名 在代筆遺囑之情形，遺囑人得以蓋章代替簽名 應以書面方式訂立之人事保證契約，雙方得以蓋章代替簽名', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 26, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00952', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於撤銷權之性質，下列敘述何者錯誤？ 撤銷權屬於形成權之一種，得因撤銷權人單方之意思表示到達相對人時，即生法律關係生效、變 更或消滅之效力 撤銷權之行使期間，不受到消滅時效規定之限制 撤銷權行使後，其撤銷之客體視為自始無效 撤銷權須法律明文規定始得發生，當事人間不得以契約約定，由一方當事人因特定事由之發生而 取得撤銷權', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00953', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '依民法規定，無權占有人返還占有物於回復請求人時，其得向回復請求人主張之權利及應負擔之義 務，下列敘述何者正確？ 善意占有人對於占有物支出之必要費用，於扣除其所收取孳息之餘額，皆得請求償還 善意占有人對於占有物因改良占有物支出之有益費用，於扣除其所收取孳息之餘額，皆得請求償還 惡意占有人對於占有物孳息之收取，推定其適法有此權利，無須返還 惡意占有人，就占有物之滅失或毀損，縱使非因可歸責於自己之事由所致者，負損害賠償之責任', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 28, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00954', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '依民法之規定，稱典權者，謂支付典價在他人之不動產為使用、收益，於他人不回贖時，取得該不 動產所有權之權。下列關於典權之敘述，何者錯誤？ 典權人對於典物因轉典所受之損害，負賠償責任 典權之約定期限超過15年時，當事人間得附有到期不贖即作絕賣之條款 典權人為典物支出有益費用，使典物增加價值，不論該增益之價值是否仍然存在，得請求出典人 償還 未定期限之典權，出典人得隨時以原典價回贖典物。但自出典後經過30年不回贖者，典權人即取 得典物所有權', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 29, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00955', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '19歲之甲經父母同意受僱於乙公司。某日甲受乙公司之吩咐，將貨物送到客戶手中。途中行經十字 路口，甲闖紅燈致丙在綠燈穿越時受傷，經該地區行車事故鑑定委員會認定，認定甲應負全部之肇 事責任。就此情形，下列敘述何者錯誤？ 甲是未成年人，對於丙之損害，無須負賠償責任 丙得主張乙與甲負連帶損害賠償責任 丙得主張甲及其父母負連帶損害賠償責任 乙賠償丙之損害後，得向甲求償', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 30, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00956', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '就賣方甲與買方乙間訂立之買賣契約，下列敘述何者錯誤？ 該買賣標的物因可歸責於甲之事由而滅失，致給付不能者，乙得解除契約並請求損害賠償 該買賣標的物因不可歸責甲乙之事由而滅失，致給付不能者，甲得免除該物之給付義務 該買賣標的物因不可歸責甲乙之事由而滅失，致給付不能者，乙得免除價金支付之義務 該買賣標的物因可歸責乙之事由而滅失，致給付不能者，甲不得向乙請求價金之支付', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 31, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00957', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關夫妻離婚後所生身分及財產上效力之說明，何者正確？ 夫妻離婚後，其子女對未享有親權之父母一方，喪失原本享有之法定繼承權 夫妻離婚後，未享有親權之父母一方與其子女間，互相不負扶養之義務 兩願離婚之場合，關於子女之親權，由夫任之 夫妻無過失之一方，因判決離婚而限於生活困難者，他方縱無過失，亦應給予贍養費', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 32, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00958', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關遺產分割之敘述，何者錯誤？ 繼承人請求分割遺產之不動產，性質上為處分行為，依民法第759條規定，於未辦妥繼承登記前， 不得為之 被繼承人之遺囑，定有分割遺產之方法，或託他人代定者，從其所定 繼承人對被繼承人已屆清償期之債務，自遺產分割時起，15年內仍負連帶責任 繼承人之一所分得之土地持分短少，得向其他繼承人請求賠償短少分配之同額價金', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 33, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00959', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關繼承之敘述，何者錯誤？ 奠儀於繼承發生時並不存在，非屬被繼承人所遺財產 繼承人對於被繼承人之債務，以因繼承所得遺產為限，負清償責任 債權人得單獨向法院聲請命繼承人於3個月內提出遺產清冊 繼承人對於遺產全部為公同共有關係，無應有部分，故若逾越應繼分比例享有（行使）權利，毋 須負返還義務', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 34, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-00960', 'real-estate', 'real-estate-moex-106-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列有關意思表示之敘述，何者錯誤？ 因錯誤或被詐欺而締結契約者，在表意人依法撤銷其意思表示之前，契約效力未定 當事人之意思表示未合致者，其契約自始未成立 買賣為諾成契約，除當事人另有約定外，縱然未訂立書面，亦不影響契約之成立 非定期行為之契約，當事人一方遲延給付者，他方當事人得定相當期限催告其履行，如債務人仍 不履行時，債權人仍須另為解約之意思表示', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "c0e0e9d38f81", "answer_pdf_sha1": "ac77058dd715", "source_family": "moex-gov-tw", "moex": {"exam_code": "106180", "c": "601", "s": "1101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "106", "exam_name": "106年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 35, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL);
